#include <stdio.h>
#include <stdlib.h>

// Structure to represent a minion
typedef struct {
    int power;
    int endurance;
} Minion;

// Comparison function for sorting minions based on power
int compareMinions(const void *a, const void *b) {
    Minion *m1 = (Minion *)a;
    Minion *m2 = (Minion *)b;
    return m2->power - m1->power;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Minion minions[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &minions[i].power, &minions[i].endurance);
        }
        qsort(minions, N, sizeof(Minion), compareMinions);
        int maxSize = 0;
        for (int i = 0; i < N; i++) {
            int totalEndurance = 0;
            int setSize = 0;
            for (int j = i; j < N; j++) {
                if (minions[j].power >= (totalEndurance + minions[j].endurance) / (setSize + 1.0)) {
                    totalEndurance += minions[j].endurance;
                    setSize++;
                }
            }
            maxSize = (maxSize > setSize) ? maxSize : setSize;
        }
        printf("%d\n", maxSize);
    }
    return 0;
}

