import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Minion implements Comparable<Minion> {
        int power;
        int endurance;
        Minion(int power, int endurance) {
            this.power = power;
            this.endurance = endurance;
        }
        @Override
        public int compareTo(Minion other) {
            return Integer.compare(other.power, this.power);
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            Minion[] minions = new Minion[N];
            for (int i = 0; i < N; i++) {
                minions[i] = new Minion(scanner.nextInt(), scanner.nextInt());
            }
            Arrays.sort(minions);
            int maxSize = 0;
            for (int i = 0; i < N; i++) {
                int totalEndurance = 0;
                int setSize = 0;
                for (int j = i; j < N; j++) {
                    if (minions[j].power >= (double)(totalEndurance + minions[j].endurance) / (setSize + 1)) {
                        totalEndurance += minions[j].endurance;
                        setSize++;
                    }
                }
                maxSize = Math.max(maxSize, setSize);
            }
            System.out.println(maxSize);
        }
    }
}

